import { _ as _export_sfc, o as openBlock, c as createElementBlock, ag as createStaticVNode } from "./chunks/framework.DNT4b13o.js";
const __pageData = JSON.parse('{"title":"Federation, Materialization, and Sync","description":"","frontmatter":{},"headers":[],"relativePath":"flashql/federation-and-sync.md","filePath":"flashql/federation-and-sync.md"}');
